    def splitString(self, s: str, k: int) -> int:
        n = len(s)
        def check(max_len):
            count = 0
            curr_len = 0
            i = 0
            while i < n:
                curr_len = 0
                while i < n and curr_len < max_len:
                    curr_len += 1
                    i += 1
                count += 1
            return count <= k

        left, right = 1, n
        ans = n
        while left <= right:
            mid = (left + right) // 2
            if check(mid):
                ans = mid
                right = mid - 1
            else:
                left = mid + 1
        return ans

class Solution:
    def optimalBST(self, keys: list[str], freq: list[int]) -> int:
        n = len(keys)
        dp = [[0] * n for _ in range(n)]

        for i in range(n):
            dp[i][i] = freq[i]

        for length in range(2, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                dp[i][j] = float('inf')
                sum_freq = sum(freq[i:j+1])

                for k in range(i, j + 1):
                    cost = (dp[i][k-1] if k > i else 0) + (dp[k+1][j] if k < j else 0) + sum_freq
                    dp[i][j] = min(dp[i][j], cost)

        return dp[0][n-1]

