    def palindromePartitioning(self, s: str) -> int:
        n = len(s)
        if n <= 1:
            return 1

        dp = [0] * (n + 1)
        dp[0] = 1

        for i in range(1, n + 1):
            for j in range(1, i + 1):
                sub = s[i - j:i]
                if sub == sub[::-1]:
                    dp[i] += dp[i - j]

