class Solution:
    def isValidParenthesisSequence(self, s: str, forbidden: list[list[str]]) -> bool:
        stack = []
        pairs = {
            ')': '(',
            '}': '{',
            ']': '['
        }
        forbidden_set = set(tuple(pair) for pair in forbidden)

        for char in s:
            if char in '({[':
                stack.append(char)
            elif char in ')}]':
                if not stack:
                    return False
                top = stack.pop()
                if pairs[char] != top:
                    return False
                if (top, char) in forbidden_set:
                    return False
            else:
                continue

        return not stack

