from collections import deque

class Solution:
    def reverseFirstK(self, queue: list[int], k: int) -> list[int]:
        q = deque(queue)
        if k > len(q) or k <= 0:
            return list(q)

        stack = []
        for _ in range(k):
            stack.append(q.popleft())

        while stack:
            q.appendleft(stack.pop())

        for _ in range(len(q) - k):
            q.append(q.popleft())

        return list(q)

