def find_provinces(isConnected):
    n = len(isConnected)
    visited = [False] * n
    count = 0

    def dfs(node):
        visited[node] = True
        for neighbor in range(n):
            if isConnected[node][neighbor] == 1 and not visited[neighbor]:
