import sys

class Solution:
    def restoreIpAddresses(self, s: str) -> list[str]:
        def isValid(s):
            if not s:
                return False
            if len(s) > 1 and s[0] == '0':
                return False
            return 0 <= int(s) <= 255

        def backtrack(s, dots, current_ip, result):
            if dots == 4:
                if not s:
                    result.append(current_ip[:-1])
                return

            for i in range(1, min(4, len(s) + 1)):
                segment = s[:i]
                if isValid(segment):
                    backtrack(s[i:], dots + 1, current_ip + segment + '.', result)

        result = []
        backtrack(s, 0, '', result)
        return result

if __name__ == '__main__':
