def solve_maze(maze):
    m = len(maze)
    n = len(maze[0])
    dp = [[0] * n for _ in range(m)]
    if maze[0][0] == 0:
        dp[0][0] = 1

    for i in range(m):
        for j in range(n):
            if maze[i][j] == 1:
                continue
            if i > 0:
                dp[i][j] += dp[i-1][j]
            if j > 0:
                dp[i][j] += dp[i][j-1]
